# 3. Create a test table
try:
    result = client.create_table('sdk_test', [
        {'name': 'sensor_id', 'type': 'text'},
        {'name': 'value', 'type': 'float'},
        {'name': 'status', 'type': 'text'},
    ])
    print(f"\u2705 Created table: sdk_test")
except Exception as e:
    print(f"\u26A0 Table may already exist: {e}")

# 4. Insert test data
import random
test_data = [
    {'sensor_id': f'S{i:03d}', 'value': round(random.uniform(20, 35), 1), 'status': random.choice(['ok', 'warn', 'error'])}
    for i in range(10)
]
client.insert('sdk_test', test_data)
print(f"\u2705 Inserted {len(test_data)} rows")
print(test_data[:3])
